{
  "mcpServers": {
    "playwright": {
      "command": "npx",
      "args": ["-y", "@playwright/mcp", "--headless"]
    },
    "github": {
      "type": "http",
      "url": "https://api.githubcopilot.com/mcp",
      "headers": {
        "Authorization": "Bearer $GITHUB_TOKEN"
      }
    },
    "postgres": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-postgres"],
      "env": {
        "POSTGRES_CONNECTION_STRING": "$DATABASE_URL"
      }
    }
  }
}

{
  "mcpServers": {
    "internal-api": {
      "type": "http",
      "url": "https://api.internal.company.com/mcp",
      "headers": {
        "Authorization": "Bearer ${API_TOKEN}",
        "X-Team-ID": "${TEAM_ID}",
        "X-Environment": "development"
      }
    }
  }
}

# Respuesta MCP mal diseñada: no dice nada accionable
{"isError": True, "content": [{"type": "text", "text": "Operation failed"}]}

# Respuesta MCP bien diseñada: metadata estructurada + explicación legible
{
    "isError": True,
    "content": [{
        "type": "text",
        "text": json.dumps({
            "errorCategory": "business",
            "isRetryable": False,
            "message": "El monto solicitado ($650) excede el límite de auto-aprobación ($500) sin revisión de un supervisor.",
            "suggestedAction": "escalate_to_human",
        })
    }]
}

{
  "permissions": {
    "deny": ["mcp__puppeteer"]
  }
}
// Patrón: mcp__<nombre-del-servidor>

{
  "permissions": {
    "allow": [
      "mcp__github__list_issues",
      "mcp__github__get_issue",
      "mcp__github__list_prs"
    ],
    "deny": ["mcp__github"]
  }
}
// Patrón: mcp__<servidor>__<nombre-de-herramienta>

{
  "permissions": {
    "deny": [
      "mcp__github__delete_repository",
      "mcp__github__delete_branch"
    ]
  }
}
// El resto de las herramientas del servidor siguen disponibles
